struct Block {
    char name;
    int width;
    int height;
    int size;
    std::vector<int> corners;
    std::vector<std::vector<std::pair<int, int>>> coords;

    Block(char name, int size, int width, int height,
          const std::vector<std::vector<std::pair<int, int>>>& coords,
          const std::vector<int>& corners)
        : name(name), size(size), width(width), height(height),
          coords(coords), corners(corners) {}
};
